mapper.select:
SELECT a.CONTRACT_NO, a.CONTRACT_YEAR, a.SUB_CD, a.DEPT_CD, a.REMARK, a.CONTRACT_ST_DT as contractStDt, a.CONTRACT_ED_DT as contractEdDt, a.REG_ID, a.REG_DT, org04.manage_nm as customerManageNm, org04.company_nm as customerCompanyNm, org04.department_nm as customerDepartmentNm, d.sw_nm as swName, c.comp_cd as partnerCompanyCd, e.dept_nm as partnerCompanyNm, c.partner_contract_cd as partnerContractCd FROM TS_WORK_SW_CONTRACT a LEFT JOIN v_organization_structure org04 ON org04.origin_Cd = a.dept_cd LEFT JOIN TS_WORK_SW_PARTNER c ON c.sub_cd = a.sub_Cd LEFT JOIN TS_WORK_SW d ON d.sw_Cd = c.sw_cd LEFT JOIN tc_dept e on e.DEPT_CD = c.COMP_CD WHERE a.DELETE_YN = 'N'
AND a.CONTRACT_YEAR = #{contractYear}
AND a.CONTRACT_NO LIKE CONCAT('%', #{contractNo}, '%')
AND org04.company_cd = #{customerCode}
AND org04.manage_cd = #{manageDeptCode}
AND c.comp_cd = #{partnerCode}
AND d.sw_nm LIKE CONCAT('%', #{swNm}, '%')
AND a.SUB_CD LIKE CONCAT('%', #{subCode}, '%')
AND c.partner_contract_cd = #{partnerContractCd}
ORDER BY a.REG_DT DESC LIMIT #{offset}, #{limit}

SELECT COUNT(*)
FROM TS_WORK_SW_CONTRACT a
LEFT JOIN v_organization_structure org04 ON org04.origin_Cd = a.dept_cd
LEFT JOIN TS_WORK_SW_PARTNER c ON c.sub_cd = a.sub_Cd
LEFT JOIN TS_WORK_SW d ON d.sw_Cd = c.sw_cd
WHERE a.DELETE_YN = 'N'

    AND a.CONTRACT_YEAR = #{contractYear}


    AND a.CONTRACT_NO LIKE CONCAT('%', #{contractNo}, '%')


    AND org04.company_cd = #{customerCode}


    AND org04.manage_cd = #{manageDeptCode}


    AND c.comp_cd = #{partnerCode}


    AND d.sw_nm LIKE CONCAT('%', #{swNm}, '%')


    AND a.SUB_CD LIKE CONCAT('%', #{subCode}, '%')


    AND c.partner_contract_cd = #{partnerContractCd}
